patch:
diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 973943790c0a..0e7109521a4c 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -8268,6 +8268,7 @@ static std::optional<bool> isImpliedCondCommonOperandWithConstants(
 /// Return true if LHS implies RHS (expanded to its components as "R0 RPred R1")
 /// is true.  Return false if LHS implies RHS is false. Otherwise, return
 /// std::nullopt if we can't infer anything.
+
 static std::optional<bool> isImpliedCondICmps(const ICmpInst *LHS,
                                               CmpInst::Predicate RPred,
                                               const Value *R0, const Value *R1,
@@ -8281,16 +8282,44 @@ static std::optional<bool> isImpliedCondICmps(const ICmpInst *LHS,
   CmpInst::Predicate LPred =
       LHSIsTrue ? LHS->getPredicate() : LHS->getInversePredicate();

+  // Canonicalize the LHS compare into a consistent relational form.
+  if (CmpInst::isRelational(LPred) && isa<ICmpInst>(LHS) &&
+      CmpInst::getSwappedPredicate(LPred) == LPred) {
+    // Nothing to do for self-swapping predicates.
+  }
+
+  // Canonicalize the RHS compare into a consistent relational form if the
+  // compare is expressed with swapped operands.
+  CmpInst::Predicate CanonRPred = RPred;
+  const Value *CanonR0 = R0;
+  const Value *CanonR1 = R1;
+
   // Can we infer anything when the two compares have matching operands?
   bool AreSwappedOps;
-  if (areMatchingOperands(L0, L1, R0, R1, AreSwappedOps))
-    return isImpliedCondMatchingOperands(LPred, RPred, AreSwappedOps);
+  if (areMatchingOperands(L0, L1, CanonR0, CanonR1, AreSwappedOps))
+    return isImpliedCondMatchingOperands(LPred, CanonRPred, AreSwappedOps);

   // Can we infer anything when the 0-operands match and the 1-operands are
   // constants (not necessarily matching)?
   const APInt *LC, *RC;
-  if (L0 == R0 && match(L1, m_APInt(LC)) && match(R1, m_APInt(RC)))
-    return isImpliedCondCommonOperandWithConstants(LPred, *LC, RPred, *RC);
+  if (L0 == CanonR0 && match(L1, m_APInt(LC)) && match(CanonR1, m_APInt(RC)))
+    return isImpliedCondCommonOperandWithConstants(LPred, *LC, CanonRPred, *RC);
+
+  // Recognize equivalent unsigned carry checks on the same add:
+  //   (add X, Y) u< X  <=>  (add X, Y) u< Y
+  //
+  // Either condition implies the other.
+  if (LPred == CmpInst::ICMP_ULT && CanonRPred == CmpInst::ICMP_ULT &&
+      L0 == CanonR0) {
+    if (const auto *BO = dyn_cast<BinaryOperator>(L0)) {
+      if (BO->getOpcode() == Instruction::Add) {
+        const Value *X = BO->getOperand(0);
+        const Value *Y = BO->getOperand(1);
+        if ((L1 == X && CanonR1 == Y) || (L1 == Y && CanonR1 == X))
+          return true;
+      }
+    }
+  }

   if (LPred == RPred)
     return isImpliedCondOperands(LPred, L0, L1, R0, R1, DL, Depth);
@@ -8298,6 +8327,7 @@ static std::optional<bool> isImpliedCondICmps(const ICmpInst *LHS,
   return std::nullopt;
 }

+
 /// Return true if LHS implies RHS is true.  Return false if LHS implies RHS is
 /// false.  Otherwise, return std::nullopt if we can't infer anything.  We
 /// expect the RHS to be an icmp and the LHS to be an 'and', 'or', or a 'select'
